_self.get(cname);if(cookieVal!=null)document.cookie=cname+"="+cookieVal+";expires="+d.toGMTString()+"; "+MainDomain};function getDomain(_domain){var domainAry=_domain.split(".");var ret="";switch(domainAry.length){case 2:ret="domain=.";ret+=_domain;break;case 3:ret="domain=.";domainAry.shift();ret+=domainAry.join(".");break;default:ret=_domain;break}return ret}};

